mapper.select:
SELECT e.STAFF_ID AS staffId, e.DEPT_ID AS deptId, e.NAME AS name, e.PHONE AS phone, e.EMAIL AS email, e.BIRTH_DATE AS birthDate, e.GENDER_CODE AS genderCode, e.ZIP_CODE AS zipCode, e.ADDRESS1 AS address1, e.ADDRESS2 AS address2, e.STATUS AS status,
d.DOCTOR_TYPE AS doctorType, d.SPECIALTY_ID AS specialtyId, d.PROFILE_SUMMARY AS doctorProfileSummary, d.DOCTOR_FILE_URL AS doctorFileUrl,
n.NURSE_TYPE AS nurseType FROM JCH.EMPLOYEE e LEFT JOIN JCH.EMPLOYEE_DOCTOR d ON e.STAFF_ID = d.STAFF_ID LEFT JOIN JCH.EMPLOYEE_NURSE n ON e.STAFF_ID = n.STAFF_ID LEFT JOIN JCH.EMPLOYEE_RECEPTION r ON e.STAFF_ID = r.STAFF_ID WHERE e.STAFF_ID = #{staffId}
